module RefModule (
    input clk,
    input rst,
    input si,
    output [7:0] po
);

    reg [7:0] unused_sr;

    always @(posedge clk or posedge rst) begin
        if (rst)
            unused_sr <= 8'b00000000;
        else
            unused_sr <= {unused_sr[6:0], si};
    end

    assign po = unused_sr;

endmodule
